```javascript
/**
 * Debounce a function — delays execution until after `wait` ms of inactivity.
 * @param {Function} func - The function to debounce
 * @param {number} wait - Milliseconds to wait
 * @param {Object} options - { leading: false, trailing: true }
 * @returns {Function} Debounced function with `cancel()` and `flush()` methods
 */
function debounce(func, wait = 300, options = {}) {
  const { leading = false, trailing = true } = options;

  let timeoutId;
  let lastArgs;
  let lastThis;
  let lastCallTime;
  let result;

  function invokeFunc() {
    return func.apply(lastThis, lastArgs);
  }

  function startTimer() {
    return setTimeout(timerExpired, wait);
  }

  function timerExpired() {
    const isInvoking = shouldInvoke(Date.now());

    if (isInvoking) {
      return trailingEdge();
    }

    timeoutId = undefined;
  }

  function trailingEdge() {
    timeoutId = undefined;

    if (trailing && lastArgs) {
      return invokeFunc();
    }

    lastArgs = lastThis = undefined;
    return result;
  }

  function shouldInvoke(time) {
    const timeSinceLastCall = time - (lastCallTime || 0);
    return lastCallTime === undefined || timeSinceLastCall >= wait;
  }

  function debounced(...args) {
    lastArgs = args;
    lastThis = this;
    lastCallTime = Date.now();

    const isInvoking = shouldInvoke(lastCallTime);

    if (!timeoutId) {
      timeoutId = startTimer();
    }

    if (isInvoking) {
      if (leading) {
        return invokeFunc();
      }
    }

    return result;
  }

  debounced.cancel = function() {
    if (timeoutId !== undefined) {
      clearTimeout(timeoutId);
    }
    timeoutId = lastArgs = lastThis = lastCallTime = undefined;
  };

  debounced.flush = function() {
    if (timeoutId !== undefined) {
      return trailingEdge();
    }
  };

  debounced.pending = function() {
    return timeoutId !== undefined;
  };

  return debounced;
}
```

**Usage:**

```javascript
// Basic usage
const search = debounce((query) => {
  console.log('Searching:', query);
}, 300);

input.addEventListener('input', (e) => search(e.target.value));

// With options
const immediate = debounce(save, 500, { leading: true, trailing: false });

// Cancel pending execution
search.cancel();

// Flush immediately
search.flush();
```

**Features:**
- **leading**: Execute on first call (before the wait)
- **trailing**: Execute after wait (default)
- **cancel()**: Abort pending execution
- **flush()**: Execute immediately and cancel timer
- **pending()**: Check if a call is queued

